import akka.actor.{Actor, ActorLogging, Props}

// Messages for the AccountActor
object AccountActor {
  case class Deposit(amount: Double)
  case class Withdraw(amount: Double)
  case object GetBalance
  case class Balance(amount: Double)
  case class OperationFailed(reason: String)

  def props: Props = Props[AccountActor]()
}

class AccountActor extends Actor with ActorLogging {
  import AccountActor._

  // Mutable balance variable, managed by the actor
  // The actor's receive method processes messages one by one,
  // ensuring that 'balance' updates are sequential and thread-safe
  // within the actor's own context without explicit synchronization primitives.
  private var balance: Double = 0.0

  override def receive: Receive = {
    case Deposit(amount) =>
      if (amount >= 0) {
        balance += amount
        sender() ! Balance(balance)
        log.info(s"Deposited $amount. New balance: $balance")
      } else {
        sender() ! OperationFailed("Deposit amount must be non-negative.")
        log.warning(s"Attempted to deposit negative amount: $amount")
      }

    case Withdraw(amount) =>
      if (amount >= 0) {
        if (balance >= amount) {
          balance -= amount
          sender() ! Balance(balance)
          log.info(s"Withdrew $amount. New balance: $balance")
        } else {
          sender() ! OperationFailed(s"Insufficient funds. Current balance: $balance, attempted withdrawal: $amount")
          log.warning(s"Insufficient funds for withdrawal of $amount. Current balance: $balance")
        }
      } else {
        sender() ! OperationFailed("Withdrawal amount must be non-negative.")
        log.warning(s"Attempted to withdraw negative amount: $amount")
      }

    case GetBalance =>
      sender() ! Balance(balance)
      log.debug(s"Balance requested: $balance")

    case unknown =>
      log.warning(s"Received unknown message: $unknown")
  }
}